    [ColumnName("PredictedLabel")]
    public bool PredictedChurned { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public sealed class ModelTrainingService
{
    private const string ModelPath = "Data/ChurnModel.zip";
    private const string DataPath = "Data/customers.csv";

    public string TrainAndSave()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<CustomerData>(
            DataPath, hasHeader: true, separatorChar: ',');

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

        var pipeline = mlContext.Transforms.Categorical
                .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
            .Append(mlContext.Transforms.Concatenate("Features",
                nameof(CustomerData.Age),
                nameof(CustomerData.Income),
                "RegionEncoded",
                nameof(CustomerData.PurchaseHistory)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        mlContext.Model.Save(model, data.Schema, ModelPath);

        return $"Model saved to {ModelPath}. " +
               $"AUC: {metrics.AreaUnderRocCurve:F4}, " +
               $"F1: {metrics.F1Score:F4}, " +
               $"Accuracy: {metrics.Accuracy:F4}";
    }

    public string GetModelPath() => Path.GetFullPath(ModelPath);
}

