using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

var trainer = new ModelTrainingService();
var result = trainer.TrainAndSave();
Console.WriteLine(result);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(trainer.GetModelPath());

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerPredictRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedChurned,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

public sealed record CustomerPredictRequest(
    float Age,
    float Income,
    string Region,
    float PurchaseHistory);

